INSERT INTO zones (city_id, zone_code, zone_code_slug, zone_name, description, max_height_ft, far, min_lot_size_sqft, max_impervious_cover_pct, setback_front_ft, setback_rear_ft, setback_side_ft, parking_requirement) VALUES ((SELECT id FROM cities WHERE slug = 'el-paso'), 'R-3', 'r-3', 'Residential Multiple-Family District', 'Intended to provide opportunities for attractive living environments at densities greater than permitted in other residential districts, encouraging high-density development of affordable single-family and multiple-family housing types.', 35, NULL, 6000, NULL, 20, NULL, NULL, 'Off-street parking required, details in Appendix C of Title 20.') ON CONFLICT (city_id, zone_code_slug) DO UPDATE SET zone_name = excluded.zone_name, description = excluded.description, max_height_ft = excluded.max_height_ft, far = excluded.far, min_lot_size_sqft = excluded.min_lot_size_sqft, max_impervious_cover_pct = excluded.max_impervious_cover_pct, setback_front_ft = excluded.setback_front_ft, setback_rear_ft = excluded.setback_rear_ft, setback_side_ft = excluded.setback_side_ft, parking_requirement = excluded.parking_requirement;
INSERT INTO zone_permitted_uses (zone_id, permitted_use_id) SELECT z.id, pu.id FROM zones z, permitted_uses pu WHERE z.zone_code_slug = 'r-3' AND z.city_id = (SELECT id FROM cities WHERE slug = 'el-paso') AND pu.name IN ('Duplex and single-family attached dwellings', 'Multiple-family dwellings and dwelling groups', 'Boardinghouses and rooming houses', 'Public schools, parochial schools, kindergartens', 'Public parks and recreational facilities', 'Churches and similar religious institutions') ON CONFLICT DO NOTHING;
INSERT INTO zones (city_id, zone_code, zone_code_slug, zone_name, description, max_height_ft, far, min_lot_size_sqft, max_impervious_cover_pct, setback_front_ft, setback_rear_ft, setback_side_ft, parking_requirement) VALUES ((SELECT id FROM cities WHERE slug = 'el-paso'), 'A-1', 'a-1', 'Apartment District', 'Intended for medium densities of dwelling units, supported by higher intensity land uses at the periphery of single-family neighborhoods, preserving overall character and architectural integrity. Permits building types designed for transition from low-density residential to other residential areas, and certain non-residential uses and support facilities.', 45, NULL, NULL, NULL, NULL, NULL, NULL, 'Details in Appendix C of Title 20. SB 840 limits parking to one space per dwelling unit or prohibits requiring a multilevel parking structure for mixed-use/multifamily residential projects.') ON CONFLICT (city_id, zone_code_slug) DO UPDATE SET zone_name = excluded.zone_name, description = excluded.description, max_height_ft = excluded.max_height_ft, far = excluded.far, min_lot_size_sqft = excluded.min_lot_size_sqft, max_impervious_cover_pct = excluded.max_impervious_cover_pct, setback_front_ft = excluded.setback_front_ft, setback_rear_ft = excluded.setback_rear_ft, setback_side_ft = excluded.setback_side_ft, parking_requirement = excluded.parking_requirement;
INSERT INTO zone_permitted_uses (zone_id, permitted_use_id) SELECT z.id, pu.id FROM zones z, permitted_uses pu WHERE z.zone_code_slug = 'a-1' AND z.city_id = (SELECT id FROM cities WHERE slug = 'el-paso') AND pu.name IN ('Multifamily dwellings', 'Office uses') ON CONFLICT DO NOTHING;
INSERT INTO zones (city_id, zone_code, zone_code_slug, zone_name, description, max_height_ft, far, min_lot_size_sqft, max_impervious_cover_pct, setback_front_ft, setback_rear_ft, setback_side_ft, parking_requirement) VALUES ((SELECT id FROM cities WHERE slug = 'el-paso'), 'A-4', 'a-4', 'Planned Apartment District', 'Promotes and preserves a diversity of residential dwelling types at the highest densities within the city, integrating compatible business and professional office uses. Allows for concentrations of population through multi-story facilities.', 45, NULL, NULL, NULL, NULL, NULL, NULL, 'Details in Appendix C of Title 20. SB 840 limits parking to one space per dwelling unit or prohibits requiring a multilevel parking structure for mixed-use/multifamily residential projects.') ON CONFLICT (city_id, zone_code_slug) DO UPDATE SET zone_name = excluded.zone_name, description = excluded.description, max_height_ft = excluded.max_height_ft, far = excluded.far, min_lot_size_sqft = excluded.min_lot_size_sqft, max_impervious_cover_pct = excluded.max_impervious_cover_pct, setback_front_ft = excluded.setback_front_ft, setback_rear_ft = excluded.setback_rear_ft, setback_side_ft = excluded.setback_side_ft, parking_requirement = excluded.parking_requirement;
