INSERT INTO zones (city_id, zone_code, zone_code_slug, zone_name, description, max_height_ft, far, min_lot_size_sqft, max_impervious_cover_pct, setback_front_ft, setback_rear_ft, setback_side_ft, parking_requirement) VALUES ((SELECT id FROM cities WHERE slug = 'el-paso'), 'C-4', 'c-4', 'Commercial District', 'Intended to serve the entire City, permitting heavy commercial uses characterized by automotive and light warehousing. Provides a transition from general business areas to industrial uses and accommodates major locations of commerce, service, and employment activities.', NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Details in Appendix C of Title 20. Some areas are eliminating parking minimums.') ON CONFLICT (city_id, zone_code_slug) DO UPDATE SET zone_name = excluded.zone_name, description = excluded.description, max_height_ft = excluded.max_height_ft, far = excluded.far, min_lot_size_sqft = excluded.min_lot_size_sqft, max_impervious_cover_pct = excluded.max_impervious_cover_pct, setback_front_ft = excluded.setback_front_ft, setback_rear_ft = excluded.setback_rear_ft, setback_side_ft = excluded.setback_side_ft, parking_requirement = excluded.parking_requirement;
