INSERT INTO zones (city_id, zone_code, zone_code_slug, zone_name, description, max_height_ft, far, min_lot_size_sqft, max_impervious_cover_pct, setback_front_ft, setback_rear_ft, setback_side_ft, parking_requirement) VALUES ((SELECT id FROM cities WHERE slug = 'el-paso'), 'GMU', 'gmu', 'General Mixed-Use District', 'Provides for large-scale developments that can function as individual neighborhoods, small-scale developments requiring flexibility due to unique design, or transitional areas between dissimilar land uses. Encourages walkability, public transportation, and pedestrian linkages.', 45, NULL, NULL, NULL, 0, 0, 0, 'Determined by Title 20 and Appendix C of the El Paso Municipal Code. On-street parking available along the corresponding frontage lines shall be counted toward the parking requirement. May also be provided within one-quarter mile of the site. SB 840 limits parking to one space per dwelling unit or prohibits requiring a multilevel parking structure for mixed-use/multifamily residential projects.') ON CONFLICT (city_id, zone_code_slug) DO UPDATE SET zone_name = excluded.zone_name, description = excluded.description, max_height_ft = excluded.max_height_ft, far = excluded.far, min_lot_size_sqft = excluded.min_lot_size_sqft, max_impervious_cover_pct = excluded.max_impervious_cover_pct, setback_front_ft = excluded.setback_front_ft, setback_rear_ft = excluded.setback_rear_ft, setback_side_ft = excluded.setback_side_ft, parking_requirement = excluded.parking_requirement;
