INSERT INTO zones (city_id, zone_code, zone_code_slug, zone_name, description, max_height_ft, far, min_lot_size_sqft, max_impervious_cover_pct, setback_front_ft, setback_rear_ft, setback_side_ft, parking_requirement) VALUES ((SELECT id FROM cities WHERE slug = 'el-paso'), 'R-F', 'r-f', 'Ranch and Farm District', 'Provides for primarily fallow or agricultural areas within the city, protecting and conserving these areas within and adjacent to urban development. Affords areas where semi-rural (very-low density) residential and agricultural uses can be maintained without impairment from higher density development.', NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Details in Appendix C of Title 20.') ON CONFLICT (city_id, zone_code_slug) DO UPDATE SET zone_name = excluded.zone_name, description = excluded.description, max_height_ft = excluded.max_height_ft, far = excluded.far, min_lot_size_sqft = excluded.min_lot_size_sqft, max_impervious_cover_pct = excluded.max_impervious_cover_pct, setback_front_ft = excluded.setback_front_ft, setback_rear_ft = excluded.setback_rear_ft, setback_side_ft = excluded.setback_side_ft, parking_requirement = excluded.parking_requirement;
